// components/dashboard/UsersTable.tsx
'use client'

import { User } from '../../types'
import { FiUserX, FiTrash2, FiMapPin, FiSearch, FiUser, FiAlertCircle } from 'react-icons/fi'
import { Loader } from '../../components/common/Loader'

interface UsersTableProps {
  users: User[]
  loading?: boolean
  onBan: (userId: string) => Promise<void>
  onDelete: (userId: string) => Promise<void>
}

export function UsersTable({ users, loading = false, onBan, onDelete }: UsersTableProps) {
  if (loading) {
    return <Loader message="Loading users..." />
  }

  if (users.length === 0) {
    return (
      <div className="text-center py-12">
        <FiUser className="mx-auto text-4xl text-text-light mb-4" />
        <p className="text-text">No users found</p>
        <p className="text-text-light">No users match your search criteria</p>
      </div>
    )
  }

  const getUserStatus = (user: User) => {
    const role = user.profile?.role
    if (role === 'banned') return 'banned'
    if (role === 'admin') return 'admin'
    return 'active'
  }

  const getUserRegion = (user: User) => {
    return user.profile?.last_location?.region || 'Unknown'
  }

  const getSearchCount = (user: User) => {
    return user.search_history?.length || 0
  }

  return (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-border">
        <thead>
          <tr className="bg-gray-50">
            <th className="px-6 py-3 text-left text-xs font-medium text-text-light uppercase tracking-wider">
              User
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-text-light uppercase tracking-wider">
              Status
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-text-light uppercase tracking-wider">
              Location
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-text-light uppercase tracking-wider">
              Searches
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-text-light uppercase tracking-wider">
              Last Seen
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-text-light uppercase tracking-wider">
              Actions
            </th>
          </tr>
        </thead>
        <tbody className="bg-white divide-y divide-border">
          {users.map((user) => {
            const status = getUserStatus(user)
            
            return (
              <tr key={user.id} className="hover:bg-gray-50">
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="flex items-center">
                    <div className="flex-shrink-0 h-10 w-10 bg-primary-light rounded-full flex items-center justify-center">
                      <span className="text-white font-medium">
                        {user.first_name[0]}{user.last_name[0]}
                      </span>
                    </div>
                    <div className="ml-4">
                      <div className="text-sm font-medium text-text">
                        {user.first_name} {user.last_name}
                      </div>
                      <div className="text-sm text-text-light">
                        {user.email}
                      </div>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                    status === 'banned'
                      ? 'bg-error/10 text-error'
                      : status === 'admin'
                      ? 'bg-primary/10 text-primary'
                      : 'bg-success/10 text-success'
                  }`}>
                    {status === 'banned' && <FiAlertCircle className="mr-1" />}
                    {status.charAt(0).toUpperCase() + status.slice(1)}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="flex items-center text-sm text-text-light">
                    <FiMapPin className="mr-2" />
                    {getUserRegion(user)}
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="flex items-center text-sm text-text-light">
                    <FiSearch className="mr-2" />
                    {getSearchCount(user)}
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-text-light">
                  {new Date(user.profile?.last_seen_at || user.updated_at).toLocaleDateString()}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                  {status !== 'banned' && (
                    <button
                      onClick={() => onBan(user.id)}
                      className="text-error hover:text-error-dark mr-4"
                    >
                      <FiUserX className="inline mr-1" />
                      Ban
                    </button>
                  )}
                  <button
                    onClick={() => onDelete(user.id)}
                    className="text-error hover:text-error-dark"
                  >
                    <FiTrash2 className="inline mr-1" />
                    Delete
                  </button>
                </td>
              </tr>
            )
          })}
        </tbody>
      </table>
    </div>
  )
}